VALUES
  ('social-worker-moex-05810', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體的領導者對團體和團體成員具備權力，下列何者對權力的敘述是正確的？', '["合法權是指因為組織對其所擁有的正式職位所賦予的權力", "資訊權是指領導者可以對任務執行方法做最後定奪的權力", "參照權是指領導者擁有完成團體目標必要卻不易獲得資訊", "專家權是指領導者針對成員的行為給予獎勵或懲處的權力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05811', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對團體衝突的敘述是正確的？', '["團體間衝突和團體內衝突均指團體成員與團體之間發生衝突", "處理衝突時，要盡可能將不相干的成員摒除在處理衝突的歷程外", "團體發生複雜度高的衝突時，切記保密原則不可向外人求助處理", "團體衝突可以是任務性與關係性衝突，也可以是健康與不健康衝突"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05812', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於團體的協同領導，請問下列敘述何者正確？', '["協同領導並無法幫助團體的領導者提升預估的正確性", "協同領導會使得團體的動力無法獲得較為周延的照顧", "協同領導會使得成員們所需要因應的關係和溝通變得較為複雜", "協同領導是指團體領導者僅能再增加一人，變成兩個人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05813', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對團體結束階段的敘述錯誤？①團體成員此時會感到焦慮不安和擔心  ②團體成員都會設法盡', '["成員會在團體中出現否認和生氣情緒", "成員們都確信結束團體之後他會過得 更好  ⑤團體領導者必須降低團體的吸引力  ⑥團體領導者要幫助成員維持已獲得的改變", "", "⑤"]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05814', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體提前結束的原因，下列敘述何者錯誤？', '["因為成員中途退出團體，不得已提前結束團體", "因為團體工作者離職或調動職務，只能提前結束團體", "想參加的成員過多造成工作者困擾而提前結束團體", "機構不願意繼續支持團體方案進行，只好提前結束團體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05815', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對於團體工作者在進行團體成效評估的敘述何者正確？', '["即使負荷量大，也不能請研究人員進行團體的評估工作", "機構都會希望團體工作者能夠說明團體方案最終的成效", "不論何種評估方法，只要能證明團體有效果就是好方法", "實務工作者會懷疑進行團體評估工作可否真的帶來好處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05816', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「以社區的核心道德價值，透過個體責任、積極的公民身分和社區的生活期望等，提供一個社會和諧的 路徑」，此稱為：', '["社會整合", "社會融合", "社群建構", "社群主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05817', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對社區的敘述，何者正確？', '["虛擬社區是指在網際網路上聚集，以共享利益為中心產生互動的一群人", "虛擬社區在國內常翻譯為「社群」，又可將之稱為「事緣社區（The Business Community）」", "「地緣社區」與「事緣社區」指的都是同住於一個地區並視為一體的一群人", "由同一宗教、種族、職業或其他共同利益所構成的人群稱為「虛擬社區」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05818', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於社會工作中社區導向取徑的敘述，何者錯誤？', '["以個別案主為中心", "以共同承擔責任為起點", "評鑑的焦點在於責任的分配與適應的調整能力", "具有預防性與前瞻性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05819', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於社區社會工作的敘述，何者錯誤？', '["又稱為「社區服務」", "目的在發展較具可近性與較有效的地方服務", "試圖尋找另類方式以滿足服務使用者需求", "希望運用本土技能與地方資源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
